// Extract and store variables for use throughout the workflow
const item = $input.first().json;

return [{
  json: {
    execution_id: item.execution_id,
    callback_url: item.callback_url || null,
    characters: item.characters,
    visual_style: item.enhanced_script.visual_style,
    image_resolution: item.config?.image_resolution || '2K',
    aspect_ratio: item.config?.aspect_ratio || '16:9',
    s3_base_path: `${item.execution_id}/scenes`
  }
}];

// Split scenes array into individual items for batch processing
const item = $input.first().json;
const scenes = $('Webhook').first().json.enhanced_script.scenes;

return scenes.map(scene => ({
  json: scene
}));

// Map scene characters to their reference images from Session 2 output
const scene = $input.first().json;
const allCharacters = $('Set Variables').first().json.characters;
const sceneCharacterNames = scene.characters || [];

const characterRefs = sceneCharacterNames
  .map(name => allCharacters.find(c => c.name === name))
  .filter(c => c && c.image_url)
  .map(c => ({
    name: c.name,
    reference_url: c.image_url,
    description: c.description
  }));

// Build scene_characters with full descriptions for the AI prompt
const sceneCharacters = sceneCharacterNames.map(name => {
  const char = allCharacters.find(c => c.name === name);
  return char || { name, description: 'No description available' };
});

return [{
  json: {
    ...scene,
    character_references: characterRefs,
    scene_characters: sceneCharacters
  }
}];

