// Parse the Anthropic response and extract frame descriptions
const item = $input.first().json;
const scene = $('Prepare Scene Data').first().json;

const responseText = item.body?.content?.[0]?.text ||
                     item.content?.[0]?.text;

if (!responseText) {
  throw new Error('No content found in Anthropic response');
}

let frameDescriptions;
try {
  // Extract JSON from response (handle markdown code blocks)
  const jsonMatch = responseText.match(/```json\n?([\s\S]*?)\n?```/) ||
                    responseText.match(/\{[\s\S]*\}/);
  const jsonStr = jsonMatch ? (jsonMatch[1] || jsonMatch[0]) : responseText;
  frameDescriptions = JSON.parse(jsonStr);
} catch (e) {
  throw new Error(`Failed to parse frame descriptions JSON: ${e.message}`);
}

// Validate required fields
if (!frameDescriptions.start_frame?.prompt || !frameDescriptions.end_frame?.prompt) {
  throw new Error('Frame descriptions missing required prompt fields');
}

return [{
  json: {
    scene_number: scene.scene_number,
    title: scene.title,
    description: scene.description,
    duration_seconds: scene.duration_seconds,
    character_references: scene.character_references,
    frame_descriptions: frameDescriptions
  }
}];

