// Poll KIE AI for start frame task completion
const item = $input.first().json;
const taskId = item.body?.data?.taskId || item.data?.taskId;

if (!taskId) {
  throw new Error('No taskId returned from KIE AI createTask for start frame');
}

const sceneData = $('Parse Frame Descriptions').first().json;
const maxAttempts = 30;
const delayMs = 10000; // 10 seconds between polls

for (let attempt = 0; attempt < maxAttempts; attempt++) {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.kie.ai/api/v1/jobs/recordInfo?taskId=${taskId}`,
    headers: {
      'Authorization': `Bearer ${$credentials.kieApiKey}`
    }
  });

  const state = response.data?.state;

  if (state === 'success') {
    const resultUrls = response.data.resultJson?.result_urls || [];
    if (resultUrls.length === 0) {
      throw new Error('KIE AI start frame succeeded but returned no image URLs');
    }
    return [{
      json: {
        ...sceneData,
        start_frame_url: resultUrls[0],
        start_frame_task_id: taskId,
        start_frame_provider: 'kie'
      }
    }];
  }

  if (state === 'fail') {
    throw new Error(`KIE AI start frame failed: ${response.data.failMsg || 'Unknown error'}`);
  }

  // States: waiting, queuing, generating - keep polling
  await new Promise(resolve => setTimeout(resolve, delayMs));
}

throw new Error('KIE AI start frame timeout after 5 minutes');

