// Normalize FAL end frame response
const item = $input.first().json;
const sceneData = $('Normalize FAL Start').first().json;

const imageUrl = item.body?.images?.[0]?.url ||
                 item.images?.[0]?.url ||
                 null;

if (!imageUrl) {
  return [{
    json: {
      ...sceneData,
      end_frame_url: null,
      end_frame_provider: 'none',
      end_frame_error: 'All providers failed for end frame'
    }
  }];
}

return [{
  json: {
    ...sceneData,
    end_frame_url: imageUrl,
    end_frame_provider: 'fal'
  }
}];

// Handle case where end frame failed on KIE but we have start frame
// Try FAL for end frame only
const sceneData = $('KIE AI - Poll Start Frame').first().json;

return [{
  json: {
    ...sceneData,
    end_frame_url: null,
    end_frame_provider: 'none',
    end_frame_error: 'KIE AI end frame generation failed'
  }
}];

// Handle case where frame descriptions failed entirely
const scene = $('Prepare Scene Data').first().json;

return [{
  json: {
    scene_number: scene.scene_number,
    scene_title: scene.title,
    scene_description: scene.description,
    duration_seconds: scene.duration_seconds,
    start_frame_url: null,
    end_frame_url: null,
    frame_descriptions: null,
    error: 'Frame description generation failed'
  }
}];

// Upload both start and end frames to S3
// Receives scene data with start_frame_url and end_frame_url from any path
const item = $input.first().json;
const executionId = $('Set Variables').first().json.execution_id;
const sceneNumber = String(item.scene_number).padStart(2, '0');
const s3Bucket = $env.S3_BUCKET || 'vdo-gen';
const s3Region = $env.S3_REGION || 'us-east-1';

const result = {
  scene_number: item.scene_number,
  scene_title: item.title || item.scene_title,
  scene_description: item.description || item.scene_description,
  duration_seconds: item.duration_seconds,
  frame_descriptions: item.frame_descriptions,
  start_frame_url: item.start_frame_url || null,
  end_frame_url: item.end_frame_url || null
};

// Upload start frame if available
if (item.start_frame_url) {
  const startFramePath = `${executionId}/scenes/${sceneNumber}/start.png`;
  const s3StartUrl = `https://${s3Bucket}.s3.${s3Region}.amazonaws.com/${startFramePath}`;

  try {
    const imageBuffer = await this.helpers.httpRequest({
      method: 'GET',
      url: item.start_frame_url,
      encoding: 'arraybuffer'
    });

    await this.helpers.httpRequest({
      method: 'PUT',
      url: s3StartUrl,
      headers: { 'Content-Type': 'image/png' },
      body: imageBuffer,
      encoding: 'arraybuffer'
    });

    result.start_frame_url = s3StartUrl;
  } catch (uploadError) {
    // Retry up to 3 times
    let uploaded = false;
    for (let retry = 0; retry < 3; retry++) {
      try {
        await new Promise(resolve => setTimeout(resolve, 2000 * (retry + 1)));
        const imageBuffer = await this.helpers.httpRequest({
          method: 'GET',
          url: item.start_frame_url,
          encoding: 'arraybuffer'
        });
        await this.helpers.httpRequest({
          method: 'PUT',
          url: s3StartUrl,
          headers: { 'Content-Type': 'image/png' },
          body: imageBuffer,
          encoding: 'arraybuffer'
        });
        result.start_frame_url = s3StartUrl;
        uploaded = true;
        break;
      } catch (e) { /* continue */ }
    }
    if (!uploaded) {
      result.start_frame_url = item.start_frame_url; // Keep original URL as fallback
    }
  }
}

// Upload end frame if available
if (item.end_frame_url) {
  const endFramePath = `${executionId}/scenes/${sceneNumber}/end.png`;
  const s3EndUrl = `https://${s3Bucket}.s3.${s3Region}.amazonaws.com/${endFramePath}`;

  try {
    const imageBuffer = await this.helpers.httpRequest({
      method: 'GET',
      url: item.end_frame_url,
      encoding: 'arraybuffer'
    });

    await this.helpers.httpRequest({
      method: 'PUT',
      url: s3EndUrl,
      headers: { 'Content-Type': 'image/png' },
      body: imageBuffer,
      encoding: 'arraybuffer'
    });

    result.end_frame_url = s3EndUrl;
  } catch (uploadError) {
    let uploaded = false;
    for (let retry = 0; retry < 3; retry++) {
      try {
        await new Promise(resolve => setTimeout(resolve, 2000 * (retry + 1)));
        const imageBuffer = await this.helpers.httpRequest({
          method: 'GET',
          url: item.end_frame_url,
          encoding: 'arraybuffer'
        });
        await this.helpers.httpRequest({
          method: 'PUT',
          url: s3EndUrl,
          headers: { 'Content-Type': 'image/png' },
          body: imageBuffer,
          encoding: 'arraybuffer'
        });
        result.end_frame_url = s3EndUrl;
        uploaded = true;
        break;
      } catch (e) { /* continue */ }
    }
    if (!uploaded) {
      result.end_frame_url = item.end_frame_url; // Keep original URL as fallback
    }
  }
}

return [{ json: result }];

// Store the processed result for loop aggregation
const item = $input.first().json;

return [{
  json: {
    scene_number: item.scene_number,
    scene_title: item.scene_title || item.title,
    scene_description: item.scene_description || item.description,
    duration_seconds: item.duration_seconds,
    start_frame_url: item.start_frame_url || null,
    end_frame_url: item.end_frame_url || null,
    frame_descriptions: item.frame_descriptions || null
  }
}];

// Aggregate all processed scene results into final response
const allItems = $input.all();
const executionId = $('Set Variables').first().json.execution_id;

const scenes = allItems.map(item => ({
  id: item.json.scene_number,
  title: item.json.scene_title,
  description: item.json.scene_description,
  duration_seconds: item.json.duration_seconds,
  start_frame_url: item.json.start_frame_url,
  end_frame_url: item.json.end_frame_url,
  frame_descriptions: item.json.frame_descriptions
}));

// Sort by scene number
scenes.sort((a, b) => a.id - b.id);

return [{
  json: {
    execution_id: executionId,
    scenes: scenes,
    total_scenes: scenes.length,
    processing_stats: {
      successful: scenes.filter(s => s.start_frame_url && s.end_frame_url).length,
      partial: scenes.filter(s => (s.start_frame_url && !s.end_frame_url) || (!s.start_frame_url && s.end_frame_url)).length,
      failed: scenes.filter(s => !s.start_frame_url && !s.end_frame_url).length
    }
  }
}];

